with open("anatomy.json", "r", encoding="utf-8") as f:
    data = json.load(f)

material = data["osteology"]["topics"]["skull"]["material"]
for m in material:
    if m["id"] in BONES:
        m["title"] = BONES[m["id"]]["title"]
        m["content"] = BONES[m["id"]]["content"]

data["osteology"]["topics"]["skull"]["material"] = material

with open("anatomy.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("updated", len(BONES), "bone topics")
for m in material:
    if m["id"] in BONES:
        print("-", m["id"], len(m["content"]))
